noncompliant:
void createReferences() {
    const int& weekdayCount = 7;    // Noncompliant - reference to literal
    const double& pi = 3.14159;     // Noncompliant - reference to literal
    const float& ratio = 0.5f;      // Noncompliant - reference to literal

    // This creates a temporary that the reference binds to
    const long& largeNum = 1000000L; // Noncompliant
}

compliant:
void createConstants() {
    const int weekdayCount = 7;      // Compliant - constant value
    const double pi = 3.14159;       // Compliant - constant value
    const float ratio = 0.5f;        // Compliant - constant value

    // Or use constexpr for compile-time constants
    constexpr long largeNum = 1000000L; // Compliant

    // References to variables are fine
    int value = getValue();
    const int& refToValue = value;    // Compliant - reference to variable
}
